/* astro-shad theme -- the three-layer token contract, neutral values.
 *
 * Every astro-shad component styles itself only through these tokens.
 * A host repo re-brands by overriding VALUES here (or in its own theme
 * file loaded after this one) -- never by editing component markup.
 *
 * 1. :root         -- raw shadcn slot custom properties (+ light overrides).
 * 2. @theme        -- semantic utilities the host repo types in its own
 *                     markup (bg-canvas, text-ink, ...). Personality lives
 *                     here: accents, radius, shadows.
 * 3. @theme inline -- bridges slot vars into Tailwind utilities so
 *                     bg-primary / text-muted-foreground etc. resolve.
 *
 * Dark is the default; html[data-theme="light"] overrides the same vars.
 */

/* ── 1. Raw shadcn slot custom properties (neutral dark) ── */
:root {
  --background:             #0a0a0a;
  --foreground:             #fafafa;
  --card:                   #171717;
  --card-foreground:        #fafafa;
  --popover:                #262626;
  --popover-foreground:     #fafafa;
  /* --primary carries the chromatic brand color (shadcn convention, aligned
   * 2026-07-20 -- was previously on --accent, a deliberate divergence that's
   * now retired so ported shadcn presets/themes drop in without remapping). */
  --primary:                #60a5fa;
  --primary-foreground:     #0a0a0a;
  --secondary:              #262626;
  --secondary-foreground:   #fafafa;
  --muted:                  #262626;
  --muted-foreground:       rgb(250 250 250 / 0.45);
  /* --accent is the neutral hover surface (shadcn convention) -- numerically
   * identical to --muted (same call the --sidebar-accent family already
   * made). --accent-foreground stays full-opacity (not muted-foreground's
   * translucent variant) since hover text should read crisp. */
  --accent:                 #262626;
  --accent-foreground:      #fafafa;
  --destructive:            #dc2626;
  --destructive-foreground: #fafafa;
  --border:                 rgb(250 250 250 / 0.12);
  --input:                  rgb(250 250 250 / 0.15);
  --ring:                   #a3a3a3;
  /* Chart scale -- monochrome lightness ramp (hex approximation of shadcn's
   * Nova-preset oklch grays, chroma 0), added 2026-07-20 as chunk 2 of the
   * /create sequencing. No registry component consumes these yet -- pure
   * token-contract prep. Values are IDENTICAL in the light override below,
   * matching the source preset (chart colors don't flip with the theme,
   * unlike every other slot here) -- not an oversight. */
  --chart-1:                #d4d4d4;
  --chart-2:                #737373;
  --chart-3:                #525252;
  --chart-4:                #404040;
  --chart-5:                #262626;
  --radius:                 0.375rem;

  /* Typography axis (data-create's Heading/Body font pickers) -- host repo
   * can override these two directly for a global rebrand; /create swaps
   * them inline per-selection (see CreateLayout.astro) alongside a
   * matching Google Fonts <link>. Both default to Inter. */
  --font-heading:            "Inter", ui-sans-serif, system-ui, sans-serif;
  --font-body:                "Inter", ui-sans-serif, system-ui, sans-serif;

  /* Sidebar gets its own surface family (shadcn convention) so a host repo
   * can brand the nav rail independently of card/popover. Neutral values
   * here mirror --card / --muted; --sidebar-accent is the hover surface,
   * same role as the root --accent token (both ≈ --muted). */
  --sidebar:                   #171717;
  --sidebar-foreground:        #fafafa;
  --sidebar-primary:           #fafafa;
  --sidebar-primary-foreground: #0a0a0a;
  --sidebar-accent:            #262626;
  --sidebar-accent-foreground: #fafafa;
  --sidebar-border:            rgb(250 250 250 / 0.12);
  --sidebar-ring:               #a3a3a3;
}

/* ── no-scrollbar utility -- used by Sidebar.astro / Combobox.astro to hide
 * a scrollable region's scrollbar chrome while staying scrollable. Lives
 * here (not per-component) so every consumer that installs either item
 * actually gets a working class -- it was referenced but never defined
 * anywhere in the project until now (a real, latent registry bug: any
 * consumer who'd installed sidebar/combobox got a dead class name). ── */
@utility no-scrollbar {
  scrollbar-width: none;
  -ms-overflow-style: none;
  &::-webkit-scrollbar {
    display: none;
  }
}

/* Typography axis application -- global, zero component markup changes
 * (same principle as the radius/color axes: every component already
 * inherits font-family from its ancestors, so setting it here is enough).
 * Headings get --font-heading, everything else --font-body. */
html {
  font-family: var(--font-body);
}
h1, h2, h3, h4, h5, h6 {
  font-family: var(--font-heading);
}

/* ── 2. Semantic utilities (host-repo vocabulary, neutral values) ── */
@theme {
  /* Surface stack -- bg-canvas, bg-surface, bg-elevated, bg-shade */
  --color-canvas:   #0a0a0a;
  --color-surface:  #171717;
  --color-elevated: #262626;
  --color-shade:    #404040;

  /* Semantic ink -- flips with the theme. text-ink, border-ink/15, ... */
  --color-ink: #fafafa;

  /* Radius is personality -- host repos change these three values. */
  --radius-sm: calc(var(--radius) - 2px);
  --radius-md: var(--radius);
  --radius-lg: calc(var(--radius) + 2px);
}

/* ── 3. shadcn slot -> Tailwind utility bridge ── */
@theme inline {
  --color-background:             var(--background);
  --color-foreground:             var(--foreground);
  --color-card:                   var(--card);
  --color-card-foreground:        var(--card-foreground);
  --color-popover:                var(--popover);
  --color-popover-foreground:     var(--popover-foreground);
  --color-primary:                var(--primary);
  --color-primary-foreground:     var(--primary-foreground);
  --color-secondary:              var(--secondary);
  --color-secondary-foreground:   var(--secondary-foreground);
  --color-muted:                  var(--muted);
  --color-muted-foreground:       var(--muted-foreground);
  --color-accent:                 var(--accent);
  --color-accent-foreground:      var(--accent-foreground);
  --color-destructive:            var(--destructive);
  --color-destructive-foreground: var(--destructive-foreground);
  --color-border:                 var(--border);
  --color-input:                  var(--input);
  --color-ring:                   var(--ring);

  --color-chart-1: var(--chart-1);
  --color-chart-2: var(--chart-2);
  --color-chart-3: var(--chart-3);
  --color-chart-4: var(--chart-4);
  --color-chart-5: var(--chart-5);

  --color-sidebar:                    var(--sidebar);
  --color-sidebar-foreground:         var(--sidebar-foreground);
  --color-sidebar-primary:            var(--sidebar-primary);
  --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
  --color-sidebar-accent:             var(--sidebar-accent);
  --color-sidebar-accent-foreground:  var(--sidebar-accent-foreground);
  --color-sidebar-border:             var(--sidebar-border);
  --color-sidebar-ring:               var(--sidebar-ring);
}

/* ── Light mode overrides ── */
[data-theme="light"] {
  --color-canvas:   #fafafa;
  --color-surface:  #ffffff;
  --color-elevated: #f5f5f5;
  --color-shade:    #e5e5e5;
  --color-ink:      #171717;

  --background:             #fafafa;
  --foreground:             #171717;
  --card:                   #ffffff;
  --card-foreground:        #171717;
  --popover:                #f5f5f5;
  --popover-foreground:     #171717;
  --primary:                #2563eb;
  --primary-foreground:     #fafafa;
  --secondary:              #e5e5e5;
  --secondary-foreground:   #171717;
  --muted:                  #f5f5f5;
  --muted-foreground:       rgb(23 23 23 / 0.50);
  --accent:                 #f5f5f5;
  --accent-foreground:      #171717;
  --border:                 rgb(23 23 23 / 0.12);
  --input:                  rgb(23 23 23 / 0.10);
  --ring:                   #737373;

  /* Same values as :root -- see the dark-block comment above the chart
   * scale for why these don't flip with the theme. */
  --chart-1:                #d4d4d4;
  --chart-2:                #737373;
  --chart-3:                #525252;
  --chart-4:                #404040;
  --chart-5:                #262626;

  --sidebar:                   #f5f5f5;
  --sidebar-foreground:        #171717;
  --sidebar-primary:           #171717;
  --sidebar-primary-foreground: #fafafa;
  --sidebar-accent:            #e5e5e5;
  --sidebar-accent-foreground: #171717;
  --sidebar-border:            rgb(23 23 23 / 0.12);
  --sidebar-ring:               #737373;
}

/* ── 4. Base color axis (data-base) -- chunk 3a of the /create sequencing,
 * added 2026-07-20. Independent of --primary/--chart-* (the brand and
 * chart axes, chunk 3b, not yet built) and of [data-theme] (light/dark) --
 * all three cross freely. Swaps the achromatic-ish scale behind
 * background/card/popover/secondary/muted/accent/ring/sidebar-non-primary.
 * Omitting `data-base` (or `data-base="neutral"`, once wired) falls
 * through to :root's own values above -- Neutral needs no block of its
 * own here.
 *
 * Values are real shadcn `/create`-tool exports (oklch), converted to hex
 * via the sRGB matrix (not eyeballed) to match this file's existing hex
 * convention. --border/--input/--sidebar-border are deliberately NOT
 * overridden per base color: this project already renders them as a
 * foreground-relative alpha overlay (see :root above), which is hue-
 * agnostic by construction -- porting shadcn's own hue-tinted solid
 * border values would be redundant work for a visually negligible result.
 *
 * `taupe`'s --secondary is real captured data, not a transcription
 * error: shadcn's own export uses a cool zinc-hued value here (hue
 * ~286) while every other slot in the same export uses taupe's actual
 * warm hue (~17-68) -- an apparent quirk in the source tool, reproduced
 * faithfully rather than "corrected". */
[data-base="olive"] {
  --background:               #0c0c09;
  --foreground:               #fbfbf9;
  --card:                     #1d1d16;
  --card-foreground:          #fbfbf9;
  --popover:                  #1d1d16;
  --popover-foreground:       #fbfbf9;
  --secondary:                #2b2b22;
  --secondary-foreground:     #fbfbf9;
  --muted:                    #2b2b22;
  --muted-foreground:         #abab9c;
  --accent:                   #2b2b22;
  --accent-foreground:        #fbfbf9;
  --ring:                     #7c7c67;
  --sidebar:                  #1d1d16;
  --sidebar-foreground:       #fbfbf9;
  --sidebar-accent:           #2b2b22;
  --sidebar-accent-foreground:#fbfbf9;
  --sidebar-ring:             #7c7c67;
}

[data-base="olive"][data-theme="light"] {
