/* ── 5. Radius axis (data-radius) -- real shadcn `/create`-tool scale,
 * confirmed via source comments in the export batch (2026-07-20): none/
 * sm/md/lg captured directly, xl assumed at 1rem (consistent step size
 * with the rest of the scale). Independent of the project's own default
 * --radius (0.375rem, unchanged above) -- this axis is purely for the
 * /create tool's radius picker, not a replacement default. */
[data-radius="none"] { --radius: 0; }
[data-radius="sm"]   { --radius: 0.45rem; }
[data-radius="md"]   { --radius: 0.625rem; }
[data-radius="lg"]   { --radius: 0.875rem; }
[data-radius="xl"]   { --radius: 1rem; }

/* ── 6. Brand color axis (data-brand) -- chunk 3b of the /create
 * sequencing, added 2026-07-20. Overrides ONLY --primary/--primary-
 * foreground/--sidebar-primary/--sidebar-primary-foreground -- the
 * chromatic slots chunk 1's accent/primary realignment consolidated onto
 * --primary. Independent of --base/--chart/[data-theme]; all cross
 * freely. Omitting `data-brand` falls through to :root's own default
 * blue (chunk 1) -- there is no "neutral" brand option, unlike base
 * color, since the brand axis IS the chromatic one.
 *
 * amber/cyan/fuchsia/indigo/orange are real, fully isolated shadcn
 * `/create`-tool exports (base color pinned to Taupe while capturing, so
 * these 4 vars read cleanly) -- converted oklch -> hex via the same sRGB
 * matrix script as the base-color axis (chunk 3a), not eyeballed.
 *
 * blue and red are APPROXIMATED, not directly captured as their own
 * "brand = X" export -- flagged here so this doesn't read as equally
 * solid data:
 *   - red reuses --destructive's own oklch values verbatim (light and
 *     dark) as a plausible stand-in for the "Red" brand color -- no
 *     distinct sidebar-primary data exists, so sidebar-primary is set
 *     equal to primary (a simplification, not a derived value).
 *   - blue is built from two real anchors that happen to already exist
 *     in this codebase's own data: the recurring decorative dark-mode
 *     --sidebar-primary value found in every neutral-base preset
 *     (oklch(0.488 0.243 264.376), independently corroborated by chart-4
 *     of the real "Blue" chart-color export landing on the exact same
 *     triple) supplies --sidebar-primary; --primary is approximated from
 *     that same chart ramp's chart-3 stop (oklch(0.546 0.245 262.881)),
 *     since chart-4 already had a confirmed real-world role (sidebar-
 *     primary) and chart-3 was the next brightest/least-saturated
 *     neighbour. Both values are mode-invariant here (chart ramps don't
 *     flip with the theme in any captured export, so neither does this
 *     approximation) -- a real "blue" brand capture would very likely
 *     produce distinct light/dark values like every other real anchor
 *     does; revisit if/when one is gathered. */
[data-brand="amber"] {
  --primary:                  #973c00;
  --primary-foreground:       #fffbeb;
  --sidebar-primary:          #fe9a00;
  --sidebar-primary-foreground:#461901;
}

[data-brand="amber"][data-theme="light"] {
